#!/usr/bin/env python3
"""
Regenerate the mel-spectrogram parity test fixtures.

Produces two files in this directory:
  parity-input.wav    — a fixed 16 kHz mono wav (5 sec of synthesized speech)
  parity-mel-ref.f32  — HF Python reference mel: (80 * 3000) f32 little-endian

The TS test loads both and confirms our extractMelSpectrogram matches within
1e-3 elementwise.

Run:
  python __tests__/fixtures/regenerate-mel-fixtures.py
"""
import subprocess
import sys
from pathlib import Path

try:
    import numpy as np
    import soundfile as sf
    from transformers import WhisperFeatureExtractor
except ImportError:
    sys.exit("install: pip install transformers soundfile numpy")

OUT = Path(__file__).parent
WAV = OUT / "parity-input.wav"
REF = OUT / "parity-mel-ref.f32"

# 1. Generate the reference wav (deterministic — uses macOS `say`)
PHRASE = "the quick brown fox jumps over the lazy dog at quarter past nine"
print(f"synthesizing {PHRASE!r} → {WAV}")
subprocess.run(
    ["say", "-v", "Alex", "--data-format=LEI16@16000", "-o", str(WAV), PHRASE],
    check=True,
)

# 2. Run HF reference extractor
audio, sr = sf.read(str(WAV))
if audio.ndim > 1:
    audio = audio.mean(axis=1)
audio = audio.astype(np.float32)
print(f"loaded audio: {audio.shape} @ {sr} Hz, peak={float(np.abs(audio).max()):.3f}")

fe = WhisperFeatureExtractor()
out = fe(audio, sampling_rate=16000, return_tensors="np")
mel = out["input_features"][0]  # (80, 3000)
print(f"reference mel: {mel.shape}, dtype={mel.dtype}, "
      f"min={mel.min():.3f}, max={mel.max():.3f}, mean={mel.mean():.3f}")

# 3. Write as raw f32 little-endian, row-major (mel_bin outer, frame inner)
mel.astype(np.float32).tofile(str(REF))
print(f"wrote {REF} ({REF.stat().st_size} bytes = 80*3000*4 = {80*3000*4})")
